using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Chat client via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tools ---
var tools = new ResearchTools();

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Use the SearchWeb tool to find relevant information (perform 2-3 searches with varied queries).
        2. Use the TakeNote tool to record key findings from each search.
        3. After gathering enough information, use GetNotes to review all your notes.
        4. Provide a well-structured summary that synthesizes your findings.
        Always cite the sources from your search results.
        """,
    tools: [
        AIFunctionFactory.Create(tools.SearchWeb),
        AIFunctionFactory.Create(tools.TakeNote),
        AIFunctionFactory.Create(tools.GetNotes),
    ]);

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

// --- Interactive loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent Ready        ║");
Console.WriteLine("║  Type a topic to research, or 'quit' ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Topic> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    Console.WriteLine($"\nResearching: {topic}\n");
    tools.ClearNotes();

    try
    {
        var response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            options: runOptions);

        Console.WriteLine("─── Research Summary ───");
        Console.WriteLine(response.Text);
        Console.WriteLine("────────────────────────\n");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}\n");
    }
}

Console.WriteLine("Goodbye!");

// --- Tool implementations ---

/// <summary>
/// Provides web search and note-taking tools for the research agent.
/// </summary>
sealed class ResearchTools
{
    private readonly List<(string Title, string Content)> _notes = [];
    private readonly HttpClient _httpClient = new();

    [Description("Search the web for information on a query. Returns a list of search results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔎 Searching: \"{query}\"");

        try
        {
            // Use Wikipedia API for real, free web search results
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=5&format=json&utf8=1";
            var json = await _httpClient.GetStringAsync(url);

            var doc = System.Text.Json.JsonDocument.Parse(json);
            var results = doc.RootElement.GetProperty("query").GetProperty("search");

            var sb = new System.Text.StringBuilder();
            sb.AppendLine($"Search results for \"{query}\":\n");

            int i = 1;
            foreach (var result in results.EnumerateArray())
            {
                var title = result.GetProperty("title").GetString();
                var snippet = result.GetProperty("snippet").GetString();
                // Strip HTML tags from the snippet
                snippet = System.Text.RegularExpressions.Regex.Replace(snippet ?? "", "<.*?>", "");

                sb.AppendLine($"{i}. **{title}**");
                sb.AppendLine($"   URL: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(title?.Replace(' ', '_') ?? "")}");
                sb.AppendLine($"   Snippet: {snippet}");
                sb.AppendLine();
                i++;
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Please try a different query.";
        }
    }

    [Description("Save a research note with a title and content for later reference.")]
    public string TakeNote(
        [Description("A short title for this note")] string title,
        [Description("The content of the note")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieve all research notes taken so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        var sb = new System.Text.StringBuilder();
        sb.AppendLine($"All research notes ({_notes.Count} total):\n");

        for (int i = 0; i < _notes.Count; i++)
        {
            var (title, content) = _notes[i];
            sb.AppendLine($"--- Note {i + 1}: {title} ---");
            sb.AppendLine(content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public void ClearNotes() => _notes.Clear();
}

