 /// <summary>
 /// Provides web search and note-taking tools for the research agent.
 /// </summary>
 sealed class ResearchTools
 {
     private readonly List<(string Title, string Content)> _notes = [];
     private readonly HttpClient _httpClient = new();

     [Description("Search the web for information on a query. Returns a list of search results with titles, snippets, and URLs.")]
     public async Task<string> SearchWeb(
         [Description("The search query to look up")] string query)
     {
         Console.WriteLine($"  🔎 Searching: \"{query}\"");

         try
         {
             // Use Wikipedia API for real, free web search results
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=5&format=json&utf8=1";
             var json = await _httpClient.GetStringAsync(url);

             var doc = System.Text.Json.JsonDocument.Parse(json);
             var results = doc.RootElement.GetProperty("query").GetProperty("search");

             var sb = new System.Text.StringBuilder();
             sb.AppendLine($"Search results for \"{query}\":\n");

             int i = 1;
             foreach (var result in results.EnumerateArray())
             {
                 var title = result.GetProperty("title").GetString();
                 var snippet = result.GetProperty("snippet").GetString();
                 // Strip HTML tags from the snippet
                 snippet = System.Text.RegularExpressions.Regex.Replace(snippet ?? "", "<.*?>", "");

                 sb.AppendLine($"{i}. **{title}**");
                 sb.AppendLine($"   URL: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(title?.Replace(' ', '_') ?? "")}");
                 sb.AppendLine($"   Snippet: {snippet}");
                 sb.AppendLine();
                 i++;
             }

             return sb.ToString();
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Please try a different query.";
         }
     }

     [Description("Save a research note with a title and content for later reference.")]
     public string TakeNote(
         [Description("A short title for this note")] string title,
         [Description("The content of the note")] string content)
     {
         _notes.Add((title, content));
         Console.WriteLine($"  📝 Note saved: \"{title}\"");
         return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
     }

     [Description("Retrieve all research notes taken so far.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
         {
             return "No notes have been taken yet.";
         }

         var sb = new System.Text.StringBuilder();
         sb.AppendLine($"All research notes ({_notes.Count} total):\n");

         for (int i = 0; i < _notes.Count; i++)
         {
             var (title, content) = _notes[i];
             sb.AppendLine($"--- Note {i + 1}: {title} ---");
             sb.AppendLine(content);
             sb.AppendLine();
         }

         return sb.ToString();
     }

     public void ClearNotes() => _notes.Clear();
 }
